/**
 * WeCreator 小程序端 — 微信登录工具
 *
 * R7 · wc-mp-dev · Sprint 1 W1
 *
 * 完整流程：
 * 1. wx.login() 获取临时 code
 * 2. POST /worker/login 发送 code 到后端
 * 3. 后端用 code 调用微信 jscode2session 换取 openid
 * 4. 后端返回 JWT 双 Token（access 2h + refresh 7d）
 * 5. 本地持久化 Token + 用户信息
 *
 * 开发环境：为保证同一设备始终映射到同一 worker,
 *   前端生成一次性 mockDeviceId 存 storage,每次登录拼入 code,
 *   后端按稳定 code → 稳定 openid 识别用户。
 *   清除小程序缓存 = 切换成新用户。
 */
import Taro from '@tarojs/taro'
import { authApi } from '../api/auth'
import { saveLoginData, clearUserData, saveProfile } from '../stores/user'

// ── 微信登录 ────────────────────────────────────────

export interface LoginOutcome {
  isNew: boolean
  isVerified: boolean
}

const MOCK_DEVICE_ID_KEY = 'wc_mock_device_id'

/**
 * 获取或生成稳定的 mock 设备 ID (仅 dev 环境使用)
 * 保证同一台设备/模拟器在清缓存前永远映射到同一个 worker
 */
function getOrCreateMockDeviceId(): string {
  let id = Taro.getStorageSync(MOCK_DEVICE_ID_KEY) as string
  if (!id) {
    id = 'dev_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 10)
    Taro.setStorageSync(MOCK_DEVICE_ID_KEY, id)
  }
  return id
}

/**
 * 组合 code: dev 环境把稳定设备 ID 拼到真实 code 后面,
 * 使 `dev_openid_${code}` 在同设备重复登录时保持不变。
 * 生产环境: 直接用 Taro.login 返回的原始 code (真实微信 5min 一次性)。
 */
function buildLoginCode(realCode: string): string {
  if (process.env.NODE_ENV === 'production') {
    return realCode
  }
  return getOrCreateMockDeviceId()
}

/**
 * 正式微信登录流程
 * @returns { isNew: boolean; isVerified: boolean }
 */
export async function wxLogin(): Promise<LoginOutcome> {
  // 1. 获取微信 code
  const loginRes = await Taro.login()
  if (!loginRes.code) {
    throw new Error('微信登录失败，未获取到 code')
  }

  // 2. 后端换取 Token (dev 环境使用稳定 mockDeviceId 代替一次性 code)
  const result = await authApi.login(buildLoginCode(loginRes.code))

  // 3. 持久化
  saveLoginData({
    accessToken: result.accessToken,
    refreshToken: result.refreshToken,
    user: result.user,
  })

  return {
    isNew: result.isNew,
    isVerified: result.user.isVerified,
  }
}

/**
 * 开发环境调试登录（跳过 wx.login，直接用指定 code）
 */
export async function devLogin(code: string): Promise<LoginOutcome> {
  const result = await authApi.login(code)

  saveLoginData({
    accessToken: result.accessToken,
    refreshToken: result.refreshToken,
    user: result.user,
  })

  return {
    isNew: result.isNew,
    isVerified: result.user.isVerified,
  }
}

// ── 状态查询 ────────────────────────────────────────

/**
 * 检查是否已登录（有 Token）
 */
export function isLoggedIn(): boolean {
  return !!Taro.getStorageSync('wc_token')
}

/**
 * 退出登录 — 清除 Token + 用户信息
 * 注意: 保留 mock 设备 ID, 下次登录仍回到同一 worker
 */
export function logout() {
  clearUserData()
}

/**
 * 开发环境专用: 重置 mock 设备 ID
 * 下次登录会创建/映射到一个新 worker (等同于换账号)
 */
export function resetMockDeviceId() {
  if (process.env.NODE_ENV !== 'production') {
    Taro.removeStorageSync(MOCK_DEVICE_ID_KEY)
  }
}

/**
 * 获取当前用户基本信息（从 Storage 读取）
 */
export function getCurrentUser() {
  const raw = Taro.getStorageSync('wc_user')
  if (!raw) return null
  try {
    return JSON.parse(raw)
  } catch {
    return null
  }
}

// ── 主动拉取档案 ────────────────────────────────────

/**
 * 获取完整个人档案并缓存
 * 通常在登录成功后或进入"我的"页面时调用
 *
 * 返回: true = profile 获取成功(用户合法), false = 失败(已自动登出)
 */
export async function fetchAndCacheProfile(): Promise<boolean> {
  try {
    const profile = await authApi.getProfile()
    saveProfile(profile)
    return true
  } catch (err: any) {
    // profile 失败通常意味着: token 过期 / worker 已被删 / 后端错误
    // request.ts 已处理 401 自动登出, 这里额外对"标记登录但用户不合法"的场景兆底:
    // 若 err message 是"登录已过期"类 (已走 forceLogout), 直接返回 false
    // 若是网络或 5xx, 保留 token 下次重试 (不自动登出以免误杀)
    const msg = err?.message || ''
    if (/登录已过期|请重新登录|Unauthorized|401/.test(msg)) {
      // 已被 request.ts 处理, 无需额外动作
      return false
    }
    // 其它错误(网络/5xx): 静默失败
    return false
  }
}

/**
 * WeCreator 小程序端 — 全局用户状态管理
 *
 * R7 · wc-mp-dev · Sprint 1 W1
 *
 * 基于 Taro Storage + React hooks 的轻量状态管理
 * 支持登录/登出事件通知，多页面状态同步
 */
import { useState, useEffect, useCallback } from 'react'
import Taro from '@tarojs/taro'
import type { WorkerUser, WorkerProfile, WorkerLevel } from '../api/auth'

// ── Storage Keys ────────────────────────────────────
const STORAGE_TOKEN = 'wc_token'
const STORAGE_REFRESH = 'wc_refresh_token'
const STORAGE_USER = 'wc_user'
const STORAGE_PROFILE = 'wc_profile'

// ── 事件总线（简单发布/订阅）───────────────────────
type Listener = () => void
const listeners = new Set<Listener>()

function emitChange() {
  listeners.forEach((fn) => fn())
}

// ── 底层读写 ────────────────────────────────────────

function getToken(): string {
  return Taro.getStorageSync(STORAGE_TOKEN) || ''
}

function getRefreshToken(): string {
  return Taro.getStorageSync(STORAGE_REFRESH) || ''
}

function getStoredUser(): WorkerUser | null {
  try {
    const raw = Taro.getStorageSync(STORAGE_USER)
    return raw ? JSON.parse(raw) : null
  } catch {
    return null
  }
}

function getStoredProfile(): WorkerProfile | null {
  try {
    const raw = Taro.getStorageSync(STORAGE_PROFILE)
    return raw ? JSON.parse(raw) : null
  } catch {
    return null
  }
}

// ── 公共写入方法（供 wx-login.ts 调用）────────────

/** 登录成功后保存 Token + 用户基本信息 */
export function saveLoginData(data: {
  accessToken: string
  refreshToken: string
  user: WorkerUser
}) {
  Taro.setStorageSync(STORAGE_TOKEN, data.accessToken)
  Taro.setStorageSync(STORAGE_REFRESH, data.refreshToken)
  Taro.setStorageSync(STORAGE_USER, JSON.stringify(data.user))
  emitChange()
}

/** 保存完整个人档案（从 /worker/profile 获取后） */
export function saveProfile(profile: WorkerProfile) {
  Taro.setStorageSync(STORAGE_PROFILE, JSON.stringify(profile))
  emitChange()
}

/** 退出登录 — 清除所有状态 */
export function clearUserData() {
  Taro.removeStorageSync(STORAGE_TOKEN)
  Taro.removeStorageSync(STORAGE_REFRESH)
  Taro.removeStorageSync(STORAGE_USER)
  Taro.removeStorageSync(STORAGE_PROFILE)
  emitChange()
}

// ── React Hook ──────────────────────────────────────

export interface UserStoreState {
  /** 是否已登录 */
  isLoggedIn: boolean
  /** JWT Access Token */
  token: string
  /** 用户基本信息（登录时返回） */
  user: WorkerUser | null
  /** 完整档案（含角色/作品，需主动拉取） */
  profile: WorkerProfile | null
  /** 便捷属性 */
  userId: number
  userType: 'worker'
  nickname: string
  avatarUrl: string
  level: WorkerLevel
  isVerified: boolean
  /** 头像首字母（无头像时使用） */
  avatarInitial: string
}

export function useUserStore(): UserStoreState {
  const [, forceUpdate] = useState(0)

  useEffect(() => {
    const handler = () => forceUpdate((n) => n + 1)
    listeners.add(handler)
    return () => { listeners.delete(handler) }
  }, [])

  const token = getToken()
  const user = getStoredUser()
  const profile = getStoredProfile()

  const displayName = user?.realName || user?.nickname || ''

  return {
    isLoggedIn: !!token,
    token,
    user,
    profile,
    userId: user?.userId ?? 0,
    userType: 'worker',
    nickname: displayName,
    avatarUrl: user?.avatarUrl || '',
    level: (user?.level || 'unverified') as WorkerLevel,
    isVerified: user?.isVerified ?? false,
    avatarInitial: displayName ? displayName[0].toUpperCase() : '?',
  }
}

/**
 * Auth Controllers — 企业端 + 零工端
 *
 * R1 · wc-auth-dev · Sprint 1 W1
 *
 * 企业端路由 /api/v1/enterprise/
 *   POST   /register        企业注册
 *   POST   /login           企业登录
 *   POST   /refresh-token   Token 续期
 *   GET    /profile         获取企业信息
 *   PUT    /profile         更新企业信息
 *
 * 零工端路由 /api/v1/worker/
 *   POST   /login           微信登录
 *   POST   /refresh-token   Token 续期
 *   POST   /bind-phone      绑定手机号
 *   POST   /verify          实名认证
 *   GET    /profile         获取个人信息
 *   PUT    /profile         更新个人信息
 *   POST   /roles           添加角色档案
 *   DELETE /roles/:id       删除角色档案
 *   POST   /portfolios      上传作品集
 *   DELETE /portfolios/:id  删除作品
 */
import {
  Controller,
  Post,
  Get,
  Put,
  Delete,
  Body,
  Param,
  UseGuards,
  Req,
  ParseIntPipe,
  HttpCode,
  HttpStatus,
} from '@nestjs/common';
import { ApiTags, ApiOperation, ApiBearerAuth } from '@nestjs/swagger';
import type { Request } from 'express';
import { Throttle } from '@nestjs/throttler';
import { AuthService } from './auth.service';
import { JwtAuthGuard } from './guards/jwt-auth.guard';
import { CurrentUser } from './decorators/current-user.decorator';
import type { CurrentUserPayload } from './decorators/current-user.decorator';
import {
  RegisterEnterpriseDto,
  LoginEnterpriseDto,
  LoginWorkerDto,
  BindPhoneDto,
  VerifyIdentityDto,
  RefreshTokenDto,
  UpdateEnterpriseDto,
  UpdateWorkerProfileDto,
  AddWorkerRoleDto,
  AddPortfolioDto,
} from './dto';

/**
 * 从 Request 中提取客户端 IP（兼容代理）
 */
function extractIp(req: Request): string {
  const forwarded = req.headers['x-forwarded-for'];
  if (typeof forwarded === 'string') return forwarded.split(',')[0].trim();
  return req.ip || req.socket?.remoteAddress || 'unknown';
}

// ============================================================
// 企业端接口
// ============================================================
@ApiTags('enterprise-auth')
@Controller('enterprise')
export class EnterpriseAuthController {
  constructor(private readonly authService: AuthService) {}

  @Post('register')
  @ApiOperation({ summary: '企业注册（信用代码 + 管理员信息）' })
  async register(@Body() dto: RegisterEnterpriseDto) {
    return this.authService.registerEnterprise(dto);
  }

  @Post('login')
  @Throttle({ default: { ttl: 60_000, limit: 20 } }) // 登录接口独立限流
  @ApiOperation({ summary: '企业登录（手机号 + 密码 → 双 Token）' })
  async login(@Body() dto: LoginEnterpriseDto, @Req() req: Request) {
    return this.authService.loginEnterprise(dto, extractIp(req));
  }

  @Post('refresh-token')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Token 续期（refreshToken → 新双 Token）' })
  async refreshToken(@Body() dto: RefreshTokenDto) {
    return this.authService.refreshToken(dto.refreshToken);
  }

  @Get('profile')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: '获取企业信息' })
  async getProfile(@CurrentUser() user: CurrentUserPayload) {
    return this.authService.getEnterpriseProfile(user.companyId!);
  }

  @Put('profile')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: '更新企业信息（名称/Logo/简介/邮箱/行业）' })
  async updateProfile(
    @CurrentUser() user: CurrentUserPayload,
    @Body() dto: UpdateEnterpriseDto,
  ) {
    return this.authService.updateEnterpriseProfile(user.companyId!, dto);
  }
}

// ============================================================
// 零工端接口
// ============================================================
@ApiTags('worker-auth')
@Controller('worker')
export class WorkerAuthController {
  constructor(private readonly authService: AuthService) {}

  @Post('login')
  @ApiOperation({ summary: '零工微信登录（wx.login code → JWT 双 Token）' })
  async login(@Body() dto: LoginWorkerDto) {
    return this.authService.loginWorker(dto);
  }

  @Post('refresh-token')
  @ApiOperation({ summary: '零工端 Token 续期（refreshToken → 新双 Token）' })
  async refreshToken(@Body() dto: RefreshTokenDto) {
    return this.authService.refreshToken(dto.refreshToken);
  }

  @Post('bind-phone')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: '绑定手机号（需已登录）' })
  async bindPhone(
    @CurrentUser() user: CurrentUserPayload,
    @Body() dto: BindPhoneDto,
  ) {
    return this.authService.bindPhone(user.userId, dto);
  }

  @Post('verify')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: '实名认证（姓名 + 身份证 → 三要素校验 + AES 加密存储）' })
  async verify(
    @CurrentUser() user: CurrentUserPayload,
    @Body() dto: VerifyIdentityDto,
  ) {
    return this.authService.verifyIdentity(user.userId, dto);
  }

  @Get('profile')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: '获取零工个人信息（含角色/作品集/钱包摘要）' })
  async getProfile(@CurrentUser() user: CurrentUserPayload) {
    return this.authService.getWorkerProfile(user.userId);
  }

  @Put('profile')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: '更新零工个人信息（昵称/头像/城市/简介/技能标签）' })
  async updateProfile(
    @CurrentUser() user: CurrentUserPayload,
    @Body() dto: UpdateWorkerProfileDto,
  ) {
    return this.authService.updateWorkerProfile(user.userId, dto);
  }

  // ── 角色档案 ──────────────────────────────────────────

  @Post('roles')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: '添加角色档案（最多 5 个）' })
  async addRole(
    @CurrentUser() user: CurrentUserPayload,
    @Body() dto: AddWorkerRoleDto,
  ) {
    return this.authService.addWorkerRole(user.userId, dto);
  }

  @Delete('roles/:id')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: '删除角色档案' })
  async deleteRole(
    @Param('id', ParseIntPipe) id: number,
    @CurrentUser() user: CurrentUserPayload,
  ) {
    return this.authService.deleteWorkerRole(user.userId, id);
  }

  // ── 作品集 ────────────────────────────────────────────

  @Post('portfolios')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @ApiOperation({ summary: '上传作品集（最多 20 件）' })
  async addPortfolio(
    @CurrentUser() user: CurrentUserPayload,
    @Body() dto: AddPortfolioDto,
  ) {
    return this.authService.addPortfolio(user.userId, dto);
  }

  @Delete('portfolios/:id')
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth('access-token')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: '删除作品' })
  async deletePortfolio(
    @Param('id', ParseIntPipe) id: number,
    @CurrentUser() user: CurrentUserPayload,
  ) {
    return this.authService.deletePortfolio(user.userId, id);
  }
}

/**
 * AuthService — 认证核心业务逻辑
 *
 * R1 · wc-auth-dev · Sprint 1 W1
 *
 * 修复清单:
 *  P0-1  Redis 登录限流 (10 fails / 5 min / IP)
 *  P0-2  verifyIdentity 补全 idCardHash (SHA-256)
 *  P0-3  零工注册时自动创建 Wallet
 *  P0-4  企业登录增加企业状态检查
 *  P1-1  Worker roles API (addWorkerRole)
 *  P1-2  Worker portfolios API (addPortfolio)
 *  P1-3  微信 userInfo nickname/avatar 支持
 */
import {
  Injectable,
  ConflictException,
  UnauthorizedException,
  BadRequestException,
  ForbiddenException,
  Logger,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { InjectRedis } from '@nestjs-modules/ioredis';
import Redis from 'ioredis';
import * as bcrypt from 'bcryptjs';
import { createHash } from 'crypto';
import { PrismaService } from '../../prisma';
import { CryptoUtil } from '../../common/utils/crypto.util';
import { JwtPayload } from './jwt.strategy';
import {
  RegisterEnterpriseDto,
  LoginEnterpriseDto,
  LoginWorkerDto,
  BindPhoneDto,
  VerifyIdentityDto,
  UpdateEnterpriseDto,
  UpdateWorkerProfileDto,
  AddWorkerRoleDto,
  AddPortfolioDto,
  RefreshTokenDto,
} from './dto';

// Redis key 前缀
const LOGIN_FAIL_PREFIX = 'auth:login_fail:';
const LOGIN_FAIL_TTL = 300;       // 5 分钟
const LOGIN_FAIL_MAX = 10;        // 最多 10 次

@Injectable()
export class AuthService {
  private readonly logger = new Logger(AuthService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly jwt: JwtService,
    private readonly config: ConfigService,
    private readonly crypto: CryptoUtil,
    @InjectRedis() private readonly redis: Redis,
  ) {}

  // ================================================================
  // 企业注册
  // ================================================================
  async registerEnterprise(dto: RegisterEnterpriseDto) {
    // 1. 检查信用代码是否已注册
    const existing = await this.prisma.company.findUnique({
      where: { creditCode: dto.creditCode },
    });
    if (existing) {
      throw new ConflictException('该企业已注册');
    }

    // 2. 加密手机号 + hash 密码 + 手机 hash索引
    const encryptedPhone = this.crypto.encrypt(dto.adminPhone);
    const phoneHash = createHash('sha256').update(dto.adminPhone).digest('hex');
    const passwordHash = await bcrypt.hash(dto.password, 10);

    // 3. 事务创建企业 + 管理员
    const result = await this.prisma.$transaction(async (tx) => {
      const company = await tx.company.create({
        data: {
          name: dto.name,
          creditCode: dto.creditCode,
          contactEmail: dto.contactEmail,
          industryTag: dto.industryTag,
        },
      });

      const admin = await tx.companyUser.create({
        data: {
          companyId: company.id,
          name: dto.adminName,
          phone: encryptedPhone,
          phoneHash,
          passwordHash,
          role: 'super_admin',
        },
      });

      return { company, admin };
    });

    this.logger.log(
      `企业注册成功: ${dto.name} (ID: ${result.company.id})`,
    );

    return {
      companyId: Number(result.company.id),
      status: result.company.status,
      message: '注册成功，等待审核',
    };
  }

  // ================================================================
  // 企业登录 (P0-1: 增加 Redis 限流 · P0-4: 企业状态检查)
  // ================================================================
  async loginEnterprise(dto: LoginEnterpriseDto, ip: string) {
    // ── 1. IP 限流检查 ──────────────────────────────
    await this.checkLoginRateLimit(ip);

    // ── 2. 查找用户（phoneHash 索引 + 旧数据回退）──
    const phoneHash = createHash('sha256').update(dto.phone).digest('hex');
    let user = await this.prisma.companyUser.findFirst({
      where: { phoneHash },
      include: { company: true },
    });

    // 旧数据回退：phoneHash 列为 null 的记录逐个解密匹配
    if (!user) {
      const legacyUsers = await this.prisma.companyUser.findMany({
        where: { phoneHash: null },
        include: { company: true },
      });
      user = legacyUsers.find((u) => {
        try {
          return this.crypto.decrypt(u.phone) === dto.phone;
        } catch {
          return false;
        }
      }) ?? null;

      // 找到后补填 phoneHash（渐进迁移）
      if (user) {
        await this.prisma.companyUser.update({
          where: { id: user.id },
          data: { phoneHash },
        });
      }
    }

    if (!user) {
      await this.recordLoginFailure(ip);
      throw new UnauthorizedException('手机号或密码错误');
    }

    // ── 3. 验证密码 ─────────────────────────────────
    const passwordValid = await bcrypt.compare(dto.password, user.passwordHash);
    if (!passwordValid) {
      await this.recordLoginFailure(ip);
      throw new UnauthorizedException('手机号或密码错误');
    }

    // ── 4. 检查用户状态 ─────────────────────────────
    if (user.status === 'disabled') {
      throw new UnauthorizedException('账号已被停用');
    }
    if (user.status === 'deleted') {
      throw new UnauthorizedException('账号已被删除');
    }

    // ── 5. 检查企业状态 (P0-4) ──────────────────────
    if (user.company.status === 'suspended') {
      throw new ForbiddenException('企业已被停用，请联系平台管理员');
    }
    // pending 状态仍允许登录，但返回提示
    const companyWarning =
      user.company.status === 'pending' ? '企业资质审核中，部分功能受限' : undefined;

    // ── 6. 生成双 Token ─────────────────────────────
    const tokens = this.generateTokens({
      sub: Number(user.id),
      companyId: Number(user.companyId),
      role: user.role,
      userType: 'company',
    });

    // ── 7. 更新登录信息 + 清除失败计数 ──────────────
    await Promise.all([
      this.prisma.companyUser.update({
        where: { id: user.id },
        data: { lastLoginAt: new Date(), lastLoginIp: ip },
      }),
      this.prisma.loginLog.create({
        data: {
          userId: user.id,
          userType: 'company',
          loginMethod: 'password',
          ip,
          result: 'success',
        },
      }),
      this.clearLoginFailure(ip),
    ]);

    return {
      ...tokens,
      user: {
        userId: Number(user.id),
        name: user.name,
        role: user.role,
        companyId: Number(user.companyId),
        companyName: user.company.name,
        companyStatus: user.company.status,
      },
      ...(companyWarning ? { warning: companyWarning } : {}),
    };
  }

  // ================================================================
  // 零工微信登录 (P0-3: 自动创建 Wallet · P1-3: nickname 支持)
  // ================================================================
  async loginWorker(dto: LoginWorkerDto) {
    // 1. 用 code 换 openid（开发环境 mock）
    const { openid, nickname: wxNickname, avatarUrl: wxAvatar } =
      await this.getWechatSession(dto.code);

    // 2. 查找或创建零工（含 Wallet）
    let worker = await this.prisma.worker.findUnique({
      where: { openid },
    });

    let isNew = false;
    if (!worker) {
      // 事务：创建零工 + 钱包
      const result = await this.prisma.$transaction(async (tx) => {
        const w = await tx.worker.create({
          data: {
            openid,
            nickname: wxNickname || null,
            avatarUrl: wxAvatar || null,
          },
        });
        // P0-3: 自动创建钱包
        await tx.wallet.create({
          data: { workerId: w.id },
        });
        return w;
      });
      worker = result;
      isNew = true;
      this.logger.log(`新零工注册: openid=${openid} (ID: ${worker.id})`);
    } else if (wxNickname && !worker.nickname) {
      // 若微信返回了昵称且用户还没设置，自动填充
      worker = await this.prisma.worker.update({
        where: { id: worker.id },
        data: {
          nickname: wxNickname,
          ...(wxAvatar && !worker.avatarUrl ? { avatarUrl: wxAvatar } : {}),
        },
      });
    }

    // 3. 生成 Token
    const tokens = this.generateTokens({
      sub: Number(worker.id),
      userType: 'worker',
    });

    return {
      ...tokens,
      isNew,
      user: {
        userId: Number(worker.id),
        nickname: worker.nickname,
        realName: worker.realName,
        avatarUrl: worker.avatarUrl,
        phone: worker.phone ? '已绑定' : null,
        isVerified: worker.isVerified,
        level: worker.level,
      },
    };
  }

  // ================================================================
  // 零工绑定手机号
  // ================================================================
  async bindPhone(workerId: number, dto: BindPhoneDto) {
    const encryptedPhone = this.crypto.encrypt(dto.phone);

    // 检查手机号是否已被其他零工绑定（遍历匹配）
    const workers = await this.prisma.worker.findMany({
      where: { phone: { not: null } },
      select: { id: true, phone: true },
    });
    const conflict = workers.find((w) => {
      try {
        return (
          this.crypto.decrypt(w.phone!) === dto.phone &&
          Number(w.id) !== workerId
        );
      } catch {
        return false;
      }
    });
    if (conflict) {
      throw new ConflictException('该手机号已被其他账号绑定');
    }

    await this.prisma.worker.update({
      where: { id: BigInt(workerId) },
      data: { phone: encryptedPhone },
    });

    return { message: '手机号绑定成功' };
  }

  // ================================================================
  // 零工实名认证 (P0-2: 补全 idCardHash)
  // ================================================================
  async verifyIdentity(workerId: number, dto: VerifyIdentityDto) {
    // 1. 校验身份证号格式（18 位 + 校验位）
    if (!this.validateIdCard(dto.idCard)) {
      throw new BadRequestException('身份证号校验位不正确');
    }

    // 2. 检查是否已实名
    const worker = await this.prisma.worker.findUnique({
      where: { id: BigInt(workerId) },
      select: { isVerified: true },
    });
    if (worker?.isVerified) {
      throw new BadRequestException('已完成实名认证，不可重复认证');
    }

    // 3. 调用三要素验证（开发环境 mock 通过）
    const verifyResult = await this.callThreeElementVerify(
      dto.realName,
      dto.idCard,
    );
    if (!verifyResult.passed) {
      throw new BadRequestException('实名认证未通过');
    }

    // 4. AES 加密身份证 + SHA-256 哈希（用于快速查找去重）
    const encryptedIdCard = this.crypto.encrypt(dto.idCard);
    const idCardHash = createHash('sha256').update(dto.idCard).digest('hex');

    // 5. 检查身份证是否已被其他人认证
    const existingVerified = await this.prisma.worker.findFirst({
      where: { idCardHash, id: { not: BigInt(workerId) } },
    });
    if (existingVerified) {
      throw new ConflictException('该身份证号已被其他账号认证');
    }

    // 6. 更新
    await this.prisma.worker.update({
      where: { id: BigInt(workerId) },
      data: {
        realName: dto.realName,
        idCardEncrypted: encryptedIdCard,
        idCardHash, // P0-2: 补全 SHA-256 哈希
        isVerified: true,
        level: 'verified',
      },
    });

    this.logger.log(`零工实名认证成功: ID=${workerId}`);
    return { message: '实名认证成功', isVerified: true };
  }

  // ================================================================
  // Token 续期
  // ================================================================
  async refreshToken(refreshToken: string) {
    try {
      const payload = this.jwt.verify(refreshToken, {
        secret: this.config.get<string>('JWT_REFRESH_SECRET'),
      }) as JwtPayload;

      // 验证用户是否仍然有效
      if (payload.userType === 'company') {
        const user = await this.prisma.companyUser.findUnique({
          where: { id: BigInt(payload.sub) },
          select: { status: true },
        });
        if (!user || user.status !== 'active') {
          throw new UnauthorizedException('账号状态异常，请重新登录');
        }
      } else if (payload.userType === 'worker') {
        const worker = await this.prisma.worker.findUnique({
          where: { id: BigInt(payload.sub) },
          select: { status: true },
        });
        if (!worker || worker.status !== 'active') {
          throw new UnauthorizedException('账号状态异常，请重新登录');
        }
      }

      const tokens = this.generateTokens({
        sub: payload.sub,
        companyId: payload.companyId,
        role: payload.role,
        userType: payload.userType,
      });

      return tokens;
    } catch (err) {
      if (err instanceof UnauthorizedException) throw err;
      throw new UnauthorizedException('refreshToken 已过期，请重新登录');
    }
  }

