  /**
   * 三要素实名认证（开发环境 mock）
   */
  private async callThreeElementVerify(
    _realName: string,
    _idCard: string,
  ): Promise<{ passed: boolean }> {
    if (this.config.get<string>('NODE_ENV') !== 'production') {
      return { passed: true };
    }
    // TODO: 生产环境调用阿里云实人认证 API
    throw new BadRequestException('实名认证服务暂未配置');
  }

  /**
   * 身份证号校验位验证（ISO 7064:1983 MOD 11-2）
   */
  private validateIdCard(idCard: string): boolean {
    if (!/^\d{17}[\dXx]$/.test(idCard)) return false;

    const weights = [7, 9, 10, 5, 8, 4, 2, 1, 6, 3, 7, 9, 10, 5, 8, 4, 2];
    const checkCodes = [
      '1', '0', 'X', '9', '8', '7', '6', '5', '4', '3', '2',
    ];

    let sum = 0;
    for (let i = 0; i < 17; i++) {
      sum += parseInt(idCard[i]) * weights[i];
    }

    const checkCode = checkCodes[sum % 11];
    return idCard[17].toUpperCase() === checkCode;
  }
}

/**
 * WeCreator 小程序端 — HTTP 请求封装
 *
 * R7 · wc-mp-dev · Sprint 1 W1
 *
 * 功能：
 * - 自动注入 Bearer Token
 * - 401 自动刷新 Token（队列机制，防并发刷新）
 * - 统一错误处理（业务错误 code !== 0）
 * - 网络异常友好提示
 */
import Taro from '@tarojs/taro'
import { clearUserData } from '../stores/user'

const BASE_URL = process.env.TARO_APP_API_BASE || 'http://localhost:3000/api/v1'

// ── Token 刷新队列 ─────────────────────────────────
let isRefreshing = false
let refreshQueue: Array<{
  resolve: (token: string) => void
  reject: (err: Error) => void
}> = []

function processRefreshQueue(error: Error | null, token?: string) {
  refreshQueue.forEach(({ resolve, reject }) => {
    if (error) reject(error)
    else resolve(token!)
  })
  refreshQueue = []
}

async function refreshToken(): Promise<string> {
  const refreshTk = Taro.getStorageSync('wc_refresh_token')
  if (!refreshTk) {
    throw new Error('无 Refresh Token')
  }

  const res = await Taro.request({
    url: `${BASE_URL}/worker/refresh-token`,
    method: 'POST',
    data: { refreshToken: refreshTk },
    header: { 'Content-Type': 'application/json' },
  })

  if (res.statusCode === 200 && res.data?.code === 0) {
    const newAccess = res.data.data.accessToken
    const newRefresh = res.data.data.refreshToken
    Taro.setStorageSync('wc_token', newAccess)
    if (newRefresh) {
      Taro.setStorageSync('wc_refresh_token', newRefresh)
    }
    return newAccess
  }

  throw new Error('Token 刷新失败')
}

async function getValidToken(): Promise<string> {
  if (isRefreshing) {
    // 正在刷新中 → 排队等待
    return new Promise((resolve, reject) => {
      refreshQueue.push({ resolve, reject })
    })
  }

  isRefreshing = true
  try {
    const token = await refreshToken()
    processRefreshQueue(null, token)
    return token
  } catch (err: any) {
    processRefreshQueue(err)
    throw err
  } finally {
    isRefreshing = false
  }
}

// ── 强制退出登录 ────────────────────────────────────
/**
 * 401 自动登出:
 * 1. 清除所有本地登录状态 (token / refresh / user / profile)
 * 2. emitChange 通知首页 UI 重渲染为登录按钮 (由 clearUserData 内部触发)
 * 3. 跳转到首页 (Tab 页用 switchTab)
 */
function forceLogout() {
  clearUserData()
  Taro.switchTab({ url: '/pages/index/index' }).catch(() => {
    // 已在首页时 switchTab 会 fail, 忽略
  })
}

// ── 统一请求接口 ────────────────────────────────────

export interface RequestOptions {
  url: string
  method?: 'GET' | 'POST' | 'PUT' | 'DELETE'
  data?: any
  needAuth?: boolean
  /** 内部重试标记 */
  _isRetry?: boolean
}

export async function request<T = any>(options: RequestOptions): Promise<T> {
  const { url, method = 'GET', data, needAuth = true, _isRetry = false } = options

  const header: Record<string, string> = {
    'Content-Type': 'application/json',
  }

  if (needAuth) {
    const token = Taro.getStorageSync('wc_token')
    if (token) {
      header['Authorization'] = `Bearer ${token}`
    }
  }

  try {
    const res = await Taro.request({
      url: `${BASE_URL}${url}`,
      method,
      data,
      header,
    })

    // ── 401: Token 过期 → 尝试刷新 ──
    if (res.statusCode === 401 && !_isRetry) {
      try {
        const newToken = await getValidToken()
        // 用新 Token 重试原请求
        return request<T>({ ...options, _isRetry: true })
      } catch {
        forceLogout()
        throw new Error('登录已过期，请重新登录')
      }
    }

    // ── 401 重试后仍失败 ──
    if (res.statusCode === 401) {
      forceLogout()
      throw new Error('登录已过期，请重新登录')
    }

    // ── 429: 限流 ──
    if (res.statusCode === 429) {
      throw new Error('操作过于频繁，请稍后再试')
    }

    // ── 5xx: 服务端错误 ──
    if (res.statusCode >= 500) {
      throw new Error('服务器开小差了，请稍后再试')
    }

    // ── 业务层错误 ──
    const body = res.data
    if (body.code !== 0) {
      throw new Error(body.message || '请求失败')
    }

    return body.data as T
  } catch (err: any) {
    // 已经是业务错误，直接抛出
    if (err.message && !err.errMsg) {
      throw err
    }
    // 网络层错误（断网、超时等）
    throw new Error('网络连接异常，请检查网络后重试')
  }
}

/**
 * WeCreator 小程序 — App 入口
 *
 * R7 · wc-mp-dev · Sprint 1 W1
 *
 * 生命周期：
 * - onLaunch: 检查登录状态 → 校验 token 有效性 → 预加载个人档案
 *   若 token 过期 或 对应 worker 已删除 (401/404),自动清除本地状态回到未登录界面
 */
import { useEffect, PropsWithChildren } from 'react'
import Taro from '@tarojs/taro'
import { isLoggedIn, fetchAndCacheProfile } from './utils/wx-login'
import { clearUserData } from './stores/user'
import './app.scss'

function App({ children }: PropsWithChildren) {
  useEffect(() => {
    // App 启动: 若 storage 里有 token → 校验有效性
    if (isLoggedIn()) {
      fetchAndCacheProfile().then((ok) => {
        if (!ok) {
          // profile 拉取失败 (token 失效 / worker 已删)
          // → 清除本地登录状态, 触发 emitChange 让首页 UI 重渲易为登录按钮
          clearUserData()
        }
      })
    }

    // 检查系统信息（用于适配安全区域等）
    try {
      const sysInfo = Taro.getSystemInfoSync()
      Taro.setStorageSync('wc_sys_info', JSON.stringify({
        statusBarHeight: sysInfo.statusBarHeight,
        screenWidth: sysInfo.screenWidth,
        screenHeight: sysInfo.screenHeight,
        platform: sysInfo.platform,
        SDKVersion: sysInfo.SDKVersion,
      }))
    } catch {
      // ignore
    }
  }, [])

  return children
}

export default App

import { useState, useEffect, useCallback } from 'react'
import { View, Text, ScrollView } from '@tarojs/components'
import Taro, { useDidShow } from '@tarojs/taro'
import { wxLogin, devLogin, isLoggedIn } from '../../utils/wx-login'
import { useUserStore } from '../../stores/user'
import { request } from '../../api/request'
import './index.scss'

const STATUS_TABS = [
  { key: 'invited',    label: '待响应' },
  { key: 'accepted',   label: '进行中' },
  { key: 'completed',  label: '已完成' },
] as const

const statusBadge: Record<string, { label: string; color: string }> = {
  invited:   { label: '待接单', color: '#faad14' },
  accepted:  { label: '执行中', color: '#1677ff' },
  rejected:  { label: '已拒绝', color: '#ff4d4f' },
  expired:   { label: '已过期', color: '#d9d9d9' },
  completed: { label: '已完成', color: '#52c41a' },
}

const modeLabel: Record<string, string> = {
  task_package: '任务包',
  daily_rate: '人天制',
}

export default function IndexPage() {
  const [loading, setLoading] = useState(false)
  // 订阅 userStore → storage 变化 (clearUserData / saveLoginData) 会自动触发重渲染
  // 代替原来的 useState(isLoggedIn()) (只读首次,无法感知 app 启动轮误表 token 时的自动登出)
  const { isLoggedIn: logged } = useUserStore()
  const [activeTab, setActiveTab] = useState<string>('invited')
  const [tasks, setTasks] = useState<any[]>([])
  const [refreshing, setRefreshing] = useState(false)

  const handleLogin = useCallback(async () => {
    if (loading) return
    setLoading(true)
    try {
      const result = await wxLogin()
      // saveLoginData 已在 wxLogin 内部触发 emitChange, userStore 会自动同步 logged=true
      if (result.isNew || !result.isVerified) {
        Taro.showToast({ title: '登录成功', icon: 'success' })
        setTimeout(() => {
          Taro.navigateTo({ url: '/subpackages/auth/pages/profile-edit/index' })
        }, 1500)
      } else {
        Taro.showToast({ title: '欢迎回来', icon: 'success' })
      }
    } catch (err: any) {
      Taro.showToast({ title: err.message || '登录失败', icon: 'none' })
    } finally {
      setLoading(false)
    }
  }, [loading])

  // 加载任务列表
  const loadTasks = useCallback(async (status: string) => {
    setRefreshing(true)
    try {
      const res: any = await request({ url: '/worker/tasks', method: 'GET', data: { status } })
      setTasks(res || [])
    } catch {
      // 忽略
    } finally {
      setRefreshing(false)
    }
  }, [])

  // 切换 Tab
  const switchTab = useCallback((key: string) => {
    setActiveTab(key)
    loadTasks(key)
  }, [loadTasks])

  // 首次加载 & 页面切回时刷新
  useEffect(() => {
    if (logged) loadTasks(activeTab)
  }, [logged])

  useDidShow(() => {
    if (logged) loadTasks(activeTab)
  })

  // 跳转任务
  const goTask = (item: any) => {
    if (item.status === 'invited') {
      Taro.navigateTo({ url: `/subpackages/task/pages/detail/index?id=${item.assignmentId}` })
    } else {
      Taro.navigateTo({ url: `/subpackages/task/pages/execute/index?id=${item.assignmentId}` })
    }
  }

  // 开发环境调试登录
  const handleDevLogin = useCallback(async () => {
    const { content, confirm } = await (Taro.showModal as any)({
      title: '🔧 开发调试登录',
      editable: true,
      placeholderText: '输入 code（如 demo_worker_2026）',
      confirmText: '登录',
    })
    if (!confirm || !content?.trim()) return
    setLoading(true)
    try {
      const result = await devLogin(content.trim())
      // 同上, devLogin 内部会触发 emitChange
      void result
      Taro.showToast({ title: `调试登录成功`, icon: 'success' })
    } catch (err: any) {
      Taro.showToast({ title: err.message || '登录失败', icon: 'none' })
    } finally {
      setLoading(false)
    }
  }, [loading])

  // ───────── 未登录 ─────────
  if (!logged) {
    return (
      <View className='login-page'>
        <View className='login-brand'>
          <Text className='brand-name' onLongPress={handleDevLogin}>WeCreator</Text>
          <Text className='brand-desc'>连接企业与创意零工的协作平台</Text>
        </View>
        {/* 开发调试快捷入口 */}
        <View className='dev-entry' onClick={handleDevLogin}>
          <Text className='dev-entry-text'>🔧 开发调试登录</Text>
        </View>
        <View className='login-features'>
          <View className='feature-item'>
            <Text className='feature-icon'>💼</Text>
            <Text className='feature-text'>海量创意项目</Text>
          </View>
          <View className='feature-item'>
            <Text className='feature-icon'>💰</Text>
            <Text className='feature-text'>合规结算保障</Text>
          </View>
          <View className='feature-item'>
            <Text className='feature-icon'>⭐</Text>
            <Text className='feature-text'>积累个人品牌</Text>
          </View>
        </View>
        <View className='login-actions'>
          <View className={`login-btn ${loading ? 'loading' : ''}`} onClick={handleLogin}>
            <Text className='login-btn-text'>{loading ? '登录中...' : '微信一键登录'}</Text>
